mapper.select:
SELECT d.* FROM device d
WHERE d.user_id = #{userId}
OR d.id IN (SELECT ud.device_id FROM user_device ud WHERE ud.user_id = #{userId})

mapper.update:
UPDATE device SET
    device_name = #{deviceName}, device_type = #{deviceType},
    status = #{status}, updated_at = #{updatedAt}
WHERE id = #{id}
